# UVM 入门

> [!abstract] 概述
> UVM（Universal Verification Methodology）是 Accellera 推出的标准化验证方法学，基于 SystemVerilog 语言，提供可重用验证组件、标准化验证结构、覆盖率驱动验证流程和事务级建模（TLM）。

---

## UVM 优势

> [!tip] 为什么选择 UVM
> 与传统验证相比，UVM 在多个维度上带来质的飞跃。

```
传统验证                    UVM 验证
────────────                ────────────
手写测试框架         →       标准测试框架
难以重用            →       可重用 VIP
平台相关            →       平台无关
手动覆盖率收集       →       自动覆盖率收集
调试困难            →       标准报告机制
```

---

## UVM 核心概念

### 1. 事务（Transaction）

```systemverilog
class my_transaction extends uvm_sequence_item;
    rand bit [31:0] addr;
    rand bit [31:0] data;
    rand bit        read_write;

    `uvm_object_utils_begin(my_transaction)
        `uvm_field_int(addr, UVM_ALL_ON)
        `uvm_field_int(data, UVM_ALL_ON)
        `uvm_field_int(read_write, UVM_ALL_ON)
    `uvm_object_utils_end

    function new(string name = "my_transaction");
        super.new(name);
    endfunction
endclass
```

### 2. 序列（Sequence）

```systemverilog
class my_sequence extends uvm_sequence#(my_transaction);
    `uvm_object_utils(my_sequence)

    function new(string name = "my_sequence");
        super.new(name);
    endfunction

    virtual task body();
        `uvm_info("SEQ", "Starting sequence", UVM_MEDIUM)
        repeat(10) begin
            `uvm_do(req)  // 创建并发送 transaction
        end
        `uvm_info("SEQ", "Sequence completed", UVM_MEDIUM)
    endtask
endclass
```

### 3. 驱动器（Driver）

```systemverilog
class my_driver extends uvm_driver#(my_transaction);
    `uvm_component_utils(my_driver)

    virtual dut_if vif;

    function new(string name, uvm_component parent);
        super.new(name, parent);
    endfunction

    function void build_phase(uvm_phase phase);
        super.build_phase(phase);
        if (!uvm_config_db#(virtual dut_if)::get(this, "", "vif", vif))
            `uvm_fatal("NOVIF", "vif not configured")
    endfunction

    virtual task run_phase(uvm_phase phase);
        forever begin
            seq_item_port.get_next_item(req);
            drive_item(req);
            seq_item_port.item_done();
        end
    endfunction

    virtual protected task drive_item(my_transaction tr);
        @(posedge vif.clk);
        vif.valid = 1'b1;
        vif.addr  = tr.addr;
        vif.wdata = tr.data;
        vif.we    = tr.read_write;
    endtask
endclass
```

### 4. 监视器（Monitor）

```systemverilog
class my_monitor extends uvm_monitor;
    `uvm_component_utils(my_monitor)

    uvm_analysis_port#(my_transaction) ap;
    virtual dut_if vif;

    function new(string name, uvm_component parent);
        super.new(name, parent);
    endfunction

    function void build_phase(uvm_phase phase);
        super.build_phase(phase);
        ap = new("ap", this);
    endfunction

    virtual task run_phase(uvm_phase phase);
        forever begin
            @(posedge vif.clk);
            if (vif.valid && vif.ready) begin
                my_transaction tr = my_transaction::type_id::create("tr");
                tr.addr  = vif.addr;
                tr.data  = vif.rdata;
                tr.kind  = vif.we ? WRITE : READ;
                ap.write(tr);
            end
        end
    endtask
endclass
```

### 5. 代理（Agent）

```systemverilog
class my_agent extends uvm_agent;
    `uvm_component_utils(my_agent)

    my_driver    m_driver;
    my_monitor   m_monitor;
    my_sequencer m_sequencer;

    function new(string name, uvm_component parent);
        super.new(name, parent);
    endfunction

    function void build_phase(uvm_phase phase);
        super.build_phase(phase);
        m_monitor = my_monitor::type_id::create("m_monitor", this);
        if (is_active == UVM_ACTIVE) begin
            m_driver    = my_driver::type_id::create("m_driver", this);
            m_sequencer = my_sequencer::type_id::create("m_sequencer", this);
        end
    endfunction

    function void connect_phase(uvm_phase phase);
        if (is_active == UVM_ACTIVE)
            m_driver.seq_item_port.connect(m_sequencer.seq_item_export);
    endfunction
endclass
```

### 6. 环境（Environment）

```systemverilog
class my_env extends uvm_env;
    `uvm_component_utils(my_env)

    my_agent      m_agent;
    my_scoreboard m_sb;

    function new(string name, uvm_component parent);
        super.new(name, parent);
    endfunction

    function void build_phase(uvm_phase phase);
        super.build_phase(phase);
        m_agent = my_agent::type_id::create("m_agent", this);
        m_sb    = my_scoreboard::type_id::create("m_sb", this);
    endfunction

    function void connect_phase(uvm_phase phase);
        m_agent.m_monitor.ap.connect(m_sb.analysis_export);
    endfunction
endclass
```

### 7. 测试用例（Test）

```systemverilog
class my_test extends uvm_test;
    `uvm_component_utils(my_test)

    my_env m_env;

    function new(string name, uvm_component parent);
        super.new(name, parent);
    endfunction

    function void build_phase(uvm_phase phase);
        super.build_phase(phase);
        m_env = my_env::type_id::create("m_env", this);
        uvm_config_db#(uvm_active_passive_enum)::set(
            this, "m_env.m_agent", "is_active", UVM_ACTIVE);
    endfunction

    function void end_of_elaboration_phase(uvm_phase phase);
        super.end_of_elaboration_phase(phase);
        print();
    endfunction
endclass
```

### 8. 顶层模块（Top Module）

```systemverilog
module tb_top;
    import uvm_pkg::*;
    `include "uvm_macros.svh"

    reg clk;
    reg rst_n;

    dut u_dut (.*);

    initial begin
        uvm_config_db#(virtual dut_if)::set(
            uvm_root::get(), "*", "vif", u_dut.vif);
        run_test("my_test");
    end

    initial begin
        clk = 0;
        forever #5 clk = ~clk;
    end
endmodule
```

