  font-weight: 700 !important;
  position: absolute !important;
  top: 50% !important;
  left: 50% !important;
  transform: translate(-50%, -50%) !important;
}

/* ── Mermaid 图表 ─────────────────────────────── */

.markdown-preview-view .mermaid-wrapper,
.markdown-preview-view .mermaid {
  background: var(--surface-1) !important;
  border-radius: var(--radius-md) !important;
  padding: 20px !important;
  margin: 1.5em 0 !important;
  border: 1px solid var(--surface-3) !important;
  text-align: center !important;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.04) !important;
}

/* ── 数学公式 ─────────────────────────────── */

.math-block {
  background: var(--surface-1) !important;
  border-radius: var(--radius-md) !important;
  padding: 16px 20px !important;
  margin: 1.2em 0 !important;
  border: 1px solid var(--surface-3) !important;
  overflow-x: auto !important;
}

.markdown-preview-view .katex-display {
  margin: 0.8em 0 !important;
}

/* ── 属性面板（Frontmatter） ─────────────────────────────── */

.metadata-container {
  background: var(--surface-1) !important;
  border-radius: var(--radius-md) !important;
  padding: 16px !important;
  margin-bottom: 24px !important;
  border: 1px solid var(--surface-3) !important;
}

.metadata-property-title {
  font-weight: 700 !important;
  font-size: 0.85em !important;
  text-transform: uppercase !important;
  letter-spacing: 0.5px !important;
  color: var(--text-muted) !important;
}

/* ── 搜索结果 ─────────────────────────────── */

.search-result-container {
  border-radius: var(--radius-md) !important;
  overflow: hidden !important;
}

.search-result-file-title {
  background: var(--surface-2) !important;
  padding: 8px 12px !important;
  font-weight: 600 !important;
  border-radius: var(--radius-sm) !important;
}

/* ── 弹出预览（Hover Preview） ─────────────────────────────── */

.popover {
  border-radius: var(--radius-lg) !important;
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.15) !important;
  border: 1px solid var(--surface-3) !important;
  overflow: hidden !important;
}

.popover .markdown-preview-view {
  padding: 16px !important;
}

/* ── 状态栏 ─────────────────────────────── */

.status-bar {
  background: var(--surface-1) !important;
  border-top: 1px solid var(--surface-3) !important;
  font-size: 0.82em !important;
}

.status-bar-item {
  padding: 4px 10px !important;
}

/* ── 标签页 ─────────────────────────────── */

.workspace-tab-header {
  border-radius: var(--radius-sm) var(--radius-sm) 0 0 !important;
}

.workspace-tab-header.is-active {
  background: var(--surface-0) !important;
  border-bottom: 2px solid var(--accent-primary) !important;
}

/* ── 面包屑导航 ─────────────────────────────── */

.breadcrumb {
  font-size: 0.85em !important;
  color: var(--text-muted) !important;
}

.breadcrumb-separator {
  color: var(--text-muted) !important;
  margin: 0 4px !important;
}

/* ── 滚动条美化 ─────────────────────────────── */

::-webkit-scrollbar {
  width: 8px !important;
  height: 8px !important;
}

::-webkit-scrollbar-track {
  background: transparent !important;
}

::-webkit-scrollbar-thumb {
  background: var(--surface-3) !important;
  border-radius: 4px !important;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--text-muted) !important;
}

/* ── 动画过渡 ─────────────────────────────── */

.markdown-preview-view * {
  transition: background-color 0.15s ease, color 0.15s ease !important;
}

/* ── 打印样式 ─────────────────────────────── */

@media print {
  .callout {
    break-inside: avoid !important;
    box-shadow: none !important;
    border: 1px solid #ddd !important;
  }

  .markdown-preview-view table {
    box-shadow: none !important;
    border: 1px solid #ddd !important;
  }

  .markdown-preview-view pre {
    box-shadow: none !important;
    border: 1px solid #ddd !important;
  }
}
